import React, { useState } from "react";
import { Link } from "react-router-dom";
import axios from "axios";
import Api from "../api/Api";



function LocationCreatedashboard() {
  const [formData, setFormData] = useState({
    locationName: "",
    zone: "",
    latitude: "",
    longitude: "",
  });
  const [showRequests, setShowRequests] = useState(false);

    const [menuOpen, setMenuOpen] = useState(false);
  

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value,
    });
  };

//   const handleCreateLocation = async (e) => {
//     e.preventDefault();

//     try {
//       await axios.post(
//         Api.create_Location,
//          {
//         ...formData,
//         latitude: Number(formData.latitude),
//         longitude: Number(formData.longitude),
//       }
//       );

//       alert("Location Created Successfully");

//       setFormData({
//         locationName: "",
//         zone: "",
//         latitude: "",
//         longitude: "",
//       });

//     } catch (error) {
//   console.log(
//     "BACKEND ERROR =>",
//     error.response?.data
//   );
// }
//   };


const handleCreateLocation = async (e) => {
  e.preventDefault();

  try {
    const res = await axios.post(
      Api.create_Location,
      {
        ...formData,
        latitude: Number(formData.latitude),
        longitude: Number(formData.longitude),
      }
    );

    alert(res.data.message);

    setFormData({
      locationName: "",
      zone: "",
      latitude: "",
      longitude: "",
    });

  } catch (error) {

    alert(
      error.response?.data?.message ||
      "Failed to create location"
    );

    console.log(
      "BACKEND ERROR =>",
      error.response?.data
    );
  }
};
  return (
    <div className="min-h-screen bg-[#4CBB17]/20">

      {/* Header */}
      {/* <div className="bg-[#4CBB17]/40 px-6 py-4">

        <div className="flex items-center justify-between">

          <div>
            <h1 className="flex items-center gap-3 text-5xl font-extrabold text-green-900">
              <img
                src="/garbageVehicle.jpeg"
                alt=""
                className="w-16 h-16 object-contain"
              />
              CleanTrack
            </h1>

            <p className="text-gray-800 mt-2">
              Smart Waste Management Control Center
            </p>
          </div>

          <Link
            to="/admin"
            className="bg-green-900 text-white px-5 py-2 rounded-xl hover:bg-green-800"
          >
            Back To Dashboard
          </Link>

        </div>

      </div> */}

      <div className="mb-8 bg-[#4CBB17]/40 px-4 md:px-6 py-3">
  <div className="flex items-center justify-between">

    {/* Logo */}
    <div>
      <h1 className="flex items-center gap-2 md:gap-3 text-3xl md:text-5xl font-extrabold text-green-900">
        <img
          src="/garbageVehicle.jpeg"
          alt=""
          className="w-10 h-10 md:w-16 md:h-16 object-contain"
        />
        CleanTrack
      </h1>

      <p className="text-gray-900 text-xs md:text-base mt-1">
        Smart Waste Management Control Center
      </p>
    </div>

    {/* Mobile Menu Button */}
    <button
      className="md:hidden text-3xl font-bold"
      onClick={() => setMenuOpen(!menuOpen)}
    >
      ☰
    </button>

    {/* Desktop Menu */}
    <div className="hidden md:flex items-center gap-8 text-lg font-semibold">

      <Link
        to="/create-account"
        className="text-green-900 hover:scale-105 transition"
      >
        Create User
      </Link>

      <button
        onClick={() => {
          setShowRequests(!showRequests);
          fetchRequests();
        }}
        className="text-green-900 hover:scale-105 transition"
      >
        View Requests
      </button>

      <Link
        to="/create-location"
        className="text-green-900 hover:scale-105 transition"
      >
        Create Locations
      </Link>

      <Link
        to="/assign-location"
        className="text-green-900 hover:scale-105 transition"
      >
        Assign Location
      </Link>

      <Link
        to="/days-report"
        className="text-green-900 hover:scale-105 transition"
      >
        Days Report
      </Link>

    </div>
  </div>

  {/* Mobile Dropdown Menu */}
  {menuOpen && (
    <div className="md:hidden mt-4 flex flex-col gap-4 text-green-900 font-semibold">

      <Link
        to="/create-account"
        onClick={() => setMenuOpen(false)}
      >
        Create User
      </Link>

      <button
        className="text-left"
        onClick={() => {
          setShowRequests(!showRequests);
          fetchRequests();
          setMenuOpen(false);
        }}
      >
        View Requests
      </button>

      <Link
        to="/create-location"
        onClick={() => setMenuOpen(false)}
      >
        Create Locations
      </Link>

      <Link
        to="/assign-location"
        onClick={() => setMenuOpen(false)}
      >
        Assign Location
      </Link>

      <Link
        to="/days-report"
        onClick={() => setMenuOpen(false)}
      >
        Days Report
      </Link>

    </div>
  )}
</div>

      {/* Page Title */}
      <div className="text-center mt-10">
        <h2 className="text-4xl font-bold text-green-900">
          Create New Location
        </h2>

        <p className="text-gray-600 mt-2">
          Add New Waste Collection Location
        </p>
      </div>

      {/* Form Card */}
      <div className="max-w-3xl mx-auto mt-10">

        <div className="bg-white rounded-3xl shadow-lg p-8 border border-green-100">

          <form
            onSubmit={handleCreateLocation}
            className="space-y-6"
          >

            {/* Location Name */}
            <div>
              <label className="block mb-2 font-semibold text-gray-700">
                Location Name
              </label>

              <input
                type="text"
                name="locationName"
                value={formData.locationName}
                onChange={handleChange}
                placeholder="Enter Location Name"
                className="w-full border border-gray-300 rounded-xl p-3 focus:outline-none focus:ring-2 focus:ring-green-500"
                required
              />
            </div>

            {/* Zone */}
            <div>
              <label className="block mb-2 font-semibold text-gray-700">
                Select Zone
              </label>

              <select
                name="zone"
                value={formData.zone}
                onChange={handleChange}
                className="w-full border border-gray-300 rounded-xl p-3"
                required
              >
                <option value="">
                  Select Zone
                </option>

                <option value="Hostel Zone 1">
                  Hostel Zone 1
                </option>

                <option value="Hostel Zone 2">
                  Hostel Zone 2
                </option>

                <option value="Academic Zone">
                  Academic Zone
                </option>

                <option value="Colony Zone">
                  Colony Zone
                </option>

              </select>
            </div>

            {/* Coordinates */}
            <div className="grid md:grid-cols-2 gap-5">

              <div>
                <label className="block mb-2 font-semibold text-gray-700">
                  Latitude
                </label>

                <input
                  type="number"
                  step="any"
                  name="latitude"
                  value={formData.latitude}
                  onChange={handleChange}
                  placeholder=""
                  className="w-full border border-gray-300 rounded-xl p-3"
                  required
                />
              </div>

              <div>
                <label className="block mb-2 font-semibold text-gray-700">
                  Longitude
                </label>

                <input
                  type="number"
                  step="any"
                  name="longitude"
                  value={formData.longitude}
                  onChange={handleChange}
                  placeholder=""
                  className="w-full border border-gray-300 rounded-xl p-3"
                  required
                />
              </div>

            </div>

            {/* Submit */}
            <button
              type="submit"
              className="w-full bg-green-900 hover:bg-green-800 text-white py-3 rounded-xl text-lg font-semibold transition"
            >
              Create Location
            </button>

          </form>

        </div>

      </div>

    </div>
  );
}

export default LocationCreatedashboard;
